#include <bits/stdc++.h>
using namespace std;
const int MAXN = 100010;
long long n,m,t[MAXN * 4],tab[MAXN * 4],tabm[MAXN * 4],mod,a[MAXN];
void push_up(int u)
{
	t[u]=(t[u*2]+t[u*2+1])%mod;
}
void push_down(int u,int l,int r)
{
	int mid=(l+r)/2;
	t[u*2]=t[u*2]*tabm[u]%mod;
	t[u*2]=(t[u*2]+(mid-l+1)*tab[u])%mod;

	tab[u*2]=tab[u*2]*tabm[u]%mod;
	tab[u*2]=(tab[u*2]+tab[u])%mod;
	tabm[u*2]=tabm[u*2]*tabm[u]%mod;

	t[u*2+1]=t[u*2+1]*tabm[u]%mod;
	t[u*2+1]=(t[u*2+1]+(r-mid)*tab[u])%mod;

	//tab[u*2+1]=tab[u]*tabm[u*2+1]%mod;
	tab[u*2+1]=tab[u*2+1]*tabm[u]%mod;
	tab[u*2+1]=(tab[u*2+1]+tab[u])%mod;
	tabm[u*2+1]=tabm[u*2+1]*tabm[u]%mod;

	tab[u]=0;
    tabm[u]=1;
}
void build(int u,int l,int r)
{
	tabm[u]=1;
	tab[u]=0;
	if(l==r)
	{
		t[u]=a[l];
		return ;
	}
	int mid=(l+r)/2;
	build(u*2,l,mid);
	build(u*2+1,mid+1,r);
	push_up(u);
}
void cheng(int u,int l,int r,int x,int y,long long k)
{
	if(l>=x&&r<=y)
	{
		t[u]=k*t[u]%mod;
		tab[u]=tab[u]*k%mod;
		tabm[u]=tabm[u]*k%mod;
		return ;
	}
	push_down(u,l,r);
	int mid=(l+r)/2;
	if(x<=mid) cheng(u*2,l,mid,x,y,k);
	if(y>mid) cheng(u*2+1,mid+1,r,x,y,k);
	push_up(u);
}
void add(int u,int l,int r,int x,int y,long long k)
{
	if(l>=x&&r<=y)
	{
		t[u]=(t[u]+k*(r-l+1))%mod;
		tab[u]=(tab[u]+k)%mod;
		return ;
	}
	push_down(u,l,r);
	int mid=(l+r)/2;
	if(x<=mid) add(u*2,l,mid,x,y,k);
	if(y>mid) add(u*2+1,mid+1,r,x,y,k);
	push_up(u);
}
long long sum(int u,int l,int r,int x,int y)
{
	if(l>=x&&r<=y) return t[u];
	push_down(u,l,r);
	int mid=(l+r)/2;
	long long ans=0;
	if(x<=mid) ans=(ans+sum(u*2,l,mid,x,y))%mod;
	if(y>mid) ans=(ans+sum(u*2+1,mid+1,r,x,y))%mod;
	return ans;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n>>m>>mod;
	for(int i=1;i<=n;i++) cin>>a[i];
	build(1,1,n);
	while(m--)
	{
		long long op,x,y,k;
		cin>>op>>x>>y;
		if(op==1)
		{
			cin>>k;
			cheng(1,1,n,x,y,k);
		}
		else if(op==2)
		{
			cin>>k;
			add(1,1,n,x,y,k);
		}
		else
		{
			cout<<sum(1,1,n,x,y)<<'\n';
		}
	}
	return 0;
}
